#include<bits/stdc++.h>
using namespace std;
long long n,m,mod,r;
long long a[100010],b[100010],X[100010],Y[100010],Z[100010],fa_bcj[100010],rnk[100010],d[100010],siz[100010],fa[100010],top[100010],dfncnt,dfn[100010],son[100010],val[100010];
vector<pair<long long,long long>> mp[100010];
long long find(long long x)
{
    return(fa[x]==x?x:fa[x]=find(fa[x]));
}
void merge(long long x,long long y)
{
    fa[find(x)]=find(y);
}
void dfs1(long long x,long long f=-1)
{
    fa[x]=f;
    siz[x]=1;
    son[x]=-1;
    for(auto i:mp[x])
    {
        long long v=i.first;
        if(v!=f)
        {
            d[v]=d[x]+1;
            dfs1(v,x);
            siz[x]+=siz[v];
            val[v]=i.second;
            if(son[x]==-1||siz[v]>siz[son[x]])
            {
                son[x]=v;
            }
        }
    }
}
void dfs2(long long x,long long t)
{
    dfn[x]=++dfncnt;
    rnk[dfncnt]=x;
    top[x]=t;
    if(son[x]!=-1)
    {
        dfs2(son[x],t);
        for(auto i:mp[x])
        {
            long long v=i.first;
            if(v!=son[x]&&v!=fa[x])
            {
                dfs2(v,v);
            }
        }
    }
}
struct segment_tree
{
    struct node
    {
        long long l,r,sum;
        long long lson,rson;
        long long tag;
        node():tag(0){}
    }a[300010];
    long long cnt;
    segment_tree():cnt(0){}
    void pushup(long long x)
    {
        a[x].sum=(a[a[x].lson].sum+a[a[x].rson].sum);
    }
    void pushdown(long long x)
    {
        long long mid=(a[x].l+a[x].r)>>1;
        long long ls=a[x].lson,rs=a[x].rson;
        long long tg=a[x].tag;
        a[ls].sum=(a[ls].sum+(mid-a[x].l+1)*tg);
        a[rs].sum=(a[rs].sum+(a[x].r-mid)*tg);
        a[ls].tag=(a[ls].tag+tg);
        a[rs].tag=(a[rs].tag+tg);
        a[x].tag=0;
    }
    long long init(long long l,long long r)
    {
        long long x=++cnt,mid=(l+r)>>1;
        a[x].l=l;
        a[x].r=r;
        if(l==r)
        {
            a[x].sum=val[rnk[l]];
            return x;
        }
        a[x].lson=init(l,mid);
        a[x].rson=init(mid+1,r);
        pushup(x);
        return x;
    }
    void add(long long x,long long l,long long r,long long z)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return;
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            a[x].sum=(a[x].sum+((a[x].r-a[x].l+1)*z));
            a[x].tag=(a[x].tag+z);
            return;
        }
        pushdown(x);
        add(a[x].lson,l,r,z);
        add(a[x].rson,l,r,z);
        pushup(x);
    }
    long long getsum(long long x,long long l,long long r)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return 0;
        }
        if(a[x].l>=l&&a[x].r<=r)
        {
            return a[x].sum;
        }
        pushdown(x);
        return (getsum(a[x].lson,l,r)+getsum(a[x].rson,l,r));
    }
}t;
long long getsum(long long x,long long y)
{
    long long ans=0;
    while(top[x]!=top[y])
    {
        if(d[top[x]]<d[top[y]])
        {
            swap(x,y);
        }
        ans+=t.getsum(1,dfn[top[x]],dfn[x]);
        x=fa[top[x]];
    }
    if(d[x]>d[y])
    {
        swap(x,y);
    }
    ans+=t.getsum(1,dfn[x]+1,dfn[y]);
    return ans;
}
void add(long long x,long long y,long long v)
{
    long long ans=0;
    while(top[x]!=top[y])
    {
        if(d[top[x]]<d[top[y]])
        {
            swap(x,y);
        }
        t.add(1,dfn[top[x]],dfn[x],v);
        x=fa[top[x]];
    }
    if(d[x]>d[y])
    {
        swap(x,y);
    }
    t.add(1,dfn[x]+1,dfn[y],v);
}
int main()
{
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=n;i++)
    {
        fa[i]=i;
    }
    long long u,v,w,id;
    for(long long i=1;i<=n;i++)
    {
        long long x,y,z;
        scanf("%lld%lld%lld",&x,&y,&z);
        X[i]=x;
        Y[i]=y;
        Z[i]=z;
        if(find(x)==find(y))
        {
            id=i;
            u=x;
            v=y;
            w=z;
            continue;
        }
        merge(x,y);
        mp[x].push_back({y,z});
        mp[y].push_back({x,z});
    }
    dfs1(1);
    dfs2(1,1);
    t.init(1,n);
    while(m--)
    {
        long long op,x,y;
        scanf("%lld%lld%lld",&op,&x,&y);
        if(op==1)
        {
            if(x==id)
            {
                w=y;
            }
            else
            {
                add(X[x],Y[x],y-Z[x]);
                Z[x]=y;
            }
        }
        else
        {
            printf("%lld\n",min({getsum(x,y),getsum(x,u)+w+getsum(v,y),getsum(x,v)+w+getsum(u,y)}));
        }
    }
    return 0;
}
